-- 1. Buat View Afiliator
DROP VIEW IF EXISTS `view_afiliator`;
CREATE VIEW `view_afiliator` AS 
SELECT `id_afiliator`, `nama_afiliator`, `email_afiliator`, `nomor_afiliator` 
FROM `afiliator`;

-- 2. Buat View Comments (Gabungan tmp_1 dan tmp_2)
DROP VIEW IF EXISTS `view_comments`;
CREATE VIEW `view_comments` AS 
SELECT `id`, `uid`, `nama`, `kehadiran`, `pesan`, `created_at` FROM `tmp_1` 
UNION 
SELECT `id`, `uid`, `nama`, `kehadiran`, `pesan`, `created_at` FROM `tmp_2`;

-- 3. Buat View Pernikahan (Query Raksasa)
DROP VIEW IF EXISTS `view_pernikahan`;
CREATE VIEW `view_pernikahan` AS 
SELECT `m`.*, `g`.`id_galeri`, `g`.`img_kategori`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/1.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_1`) END) AS `img_1`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/2.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_2`) END) AS `img_2`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/3.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_3`) END) AS `img_3`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/4.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_4`) END) AS `img_4`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/5.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_5`) END) AS `img_5`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/6.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_6`) END) AS `img_6`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/7.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_7`) END) AS `img_7`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/8.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_8`) END) AS `img_8`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/9.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_9`) END) AS `img_9`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/10.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_10`) END) AS `img_10`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/11.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_11`) END) AS `img_11`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/12.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_12`) END) AS `img_12`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/13.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_13`) END) AS `img_13`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/14.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_14`) END) AS `img_14`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/15.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_15`) END) AS `img_15`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/16.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_16`) end) AS `img_16`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/17.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_17`) end) AS `img_17`,
(CASE WHEN (COALESCE(`g`.`img_kategori`,'') <> '') THEN CONCAT(`g`.`img_kategori`,'/18.jpg') ELSE CONCAT(`g`.`uid`,'/',`g`.`img_18`) end) AS `img_18`,
(CASE WHEN ((`m`.`tgl_pernikahan` IS NOT NULL) AND (`m`.`tgl_text` IS NOT NULL) AND (`m`.`akad_text` IS NOT NULL)) THEN 1 ELSE NULL END) AS `akses_img`,
`a`.`id_afiliator`, `a`.`nama_afiliator`, `a`.`email_afiliator` 
FROM `master` `m` 
JOIN `galeri` `g` ON `m`.`uid` = `g`.`uid` 
LEFT JOIN `afiliator` `a` ON `m`.`nomor_afiliator` = `a`.`nomor_afiliator`;







